const location = String(args.location ?? 'Bangkok');
const unit = String(args.unit ?? 'celsius');

// Example: fetch from open weather API
const response = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=13.7563&longitude=100.5018&current_weather=true`);
const data = await response.json();

if (data.current_weather) {
  const w = data.current_weather;
  return `🌤️ Weather in ${location}:\n• Temperature: ${w.temperature}°${unit === 'fahrenheit' ? 'F' : 'C'}\n• Wind: ${w.windspeed} km/h\n• Code: ${w.weathercode}`;
}

